// 48 additional exercises in the same style as src/data/exercises.ts.
// Kept in a separate file to keep the main exercises file manageable.
// Translations: EN/DA/SV/NO authored; DE+AR fall back to EN (matches the pattern
// used by many existing entries in exercises.ts).

import type { ExerciseCategory, MuscleGroup } from "./exercises";

interface L {
  name: string;
  notes: string;
  whyItMatters: string;
  alternatives?: { name: string; reason: string }[];
}

interface Base {
  id: string;
  category: ExerciseCategory;
  muscleGroups: MuscleGroup[];
  sets: number;
  reps: string;
  tempo?: string;
  rest: string;
  videoId: string;
  en: L; da: L; sv: L; de: L; ar: L; no: L;
}

// Compact builder — DE and AR mirror EN (matches existing fallback pattern).
const E = (
  meta: Omit<Base, "en" | "da" | "sv" | "de" | "ar" | "no">,
  en: L, da: L, sv: L, no: L,
): Base => ({ ...meta, en, da, sv, no, de: en, ar: en });

